patch:
diff --git a/llvm/lib/Transforms/Scalar/GVN.cpp b/llvm/lib/Transforms/Scalar/GVN.cpp
index 7704e49c499d..180206f0714b 100644
--- a/llvm/lib/Transforms/Scalar/GVN.cpp
+++ b/llvm/lib/Transforms/Scalar/GVN.cpp
@@ -3191,9 +3191,11 @@ bool GVNPass::splitCriticalEdges() {
   bool Changed = false;
   do {
     std::pair<Instruction *, unsigned> Edge = ToSplit.pop_back_val();
-    Changed |= SplitCriticalEdge(Edge.first, Edge.second,
-                                 CriticalEdgeSplittingOptions(DT, LI, MSSAU)) !=
-               nullptr;
+    if (!isa<IndirectBrInst>(Edge.first)) {
+  Changed |= SplitCriticalEdge(Edge.first, Edge.second,
+                                CriticalEdgeSplittingOptions(DT, LI, MSSAU)) !=
+              nullptr;
+}
   } while (!ToSplit.empty());
   if (Changed) {
     if (MD)
@@ -3308,8 +3310,10 @@ void GVNPass::addDeadBlock(BasicBlock *BB) {

       if (is_contained(successors(P), B) &&
           isCriticalEdge(P->getTerminator(), B)) {
-        if (BasicBlock *S = splitCriticalEdges(P, B))
-          DeadBlocks.insert(P = S);
+        if (!isa<IndirectBrInst>(P->getTerminator())) {
+          if (BasicBlock *S = splitCriticalEdges(P, B))
+            DeadBlocks.insert(P = S);
+        }
       }
     }

